import{_ as a,o as d,c as o,ae as i}from"./chunks/framework.B1UF-_vb.js";const b=JSON.parse('{"title":"Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"changelog.md","filePath":"changelog.md"}'),l={name:"changelog.md"};function t(r,e,n,c,s,h){return d(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><p>All notable changes to oneagent are documented here.</p><h2 id="_0-10-3-2026-03-17" tabindex="-1">[0.10.3] - 2026-03-17 <a class="header-anchor" href="#_0-10-3-2026-03-17" aria-label="Permalink to &quot;[0.10.3] - 2026-03-17&quot;">​</a></h2><h3 id="fixed" tabindex="-1">Fixed <a class="header-anchor" href="#fixed" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Codex backend now uses <code>--dangerously-bypass-approvals-and-sandbox</code> instead of <code>--full-auto</code> — bubblewrap sandbox fails on some kernels, blocking all writes.</li></ul><h2 id="_0-10-2-2026-03-17" tabindex="-1">[0.10.2] - 2026-03-17 <a class="header-anchor" href="#_0-10-2-2026-03-17" aria-label="Permalink to &quot;[0.10.2] - 2026-03-17&quot;">​</a></h2><h3 id="added" tabindex="-1">Added <a class="header-anchor" href="#added" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>File locking on thread storage — <code>LoadThread</code> acquires a shared lock, <code>SaveThread</code> acquires an exclusive lock, preventing corruption when multiple processes (e.g., a bot and a cron job) access the same thread concurrently.</li><li>Turn attribution — <code>Turn.Source</code> field and <code>RunOpts.Source</code> let callers tag who produced a turn (e.g., <code>&quot;telegram&quot;</code>, <code>&quot;cron-nightly&quot;</code>, <code>&quot;ci-pipeline&quot;</code>).</li><li>Post-run hooks — <code>RunOpts.OnComplete</code> and <code>--on-complete</code> CLI flag execute a command after a thread turn completes, with the result piped to stdin and <code>OA_THREAD_ID</code>, <code>OA_BACKEND</code>, <code>OA_SESSION</code>, <code>OA_SOURCE</code> set as environment variables. Best-effort: hook failures are logged but don&#39;t fail the response.</li></ul><h2 id="_0-10-1-2026-03-16" tabindex="-1">[0.10.1] - 2026-03-16 <a class="header-anchor" href="#_0-10-1-2026-03-16" aria-label="Permalink to &quot;[0.10.1] - 2026-03-16&quot;">​</a></h2><h3 id="added-1" tabindex="-1">Added <a class="header-anchor" href="#added-1" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Activity events for the OpenCode backend — tool use (file reads, patches) now appears in JSONL streaming output.</li><li><code>oa-dispatch</code> agent skill for dispatching tasks to other agents, following the <a href="https://agentskills.io" target="_blank" rel="noreferrer">agentskills.io</a> spec. Install with <code>npx skills add 1broseidon/oneagent --skill oa-dispatch</code>.</li></ul><h3 id="improved" tabindex="-1">Improved <a class="header-anchor" href="#improved" aria-label="Permalink to &quot;Improved&quot;">​</a></h3><ul><li>Rewrote all public-facing docs for clarity and correctness: README, library guide, config reference, integration example, and changelog.</li><li>README now leads with a clear value proposition and includes prerequisites.</li><li>Library docs updated to use the Client-based API introduced in 0.9.0.</li><li>Integration example replaced with a complete, runnable <code>main.go</code>.</li><li>Config docs include all four backend examples with verified minimum flags for non-interactive execution.</li></ul><h3 id="fixed-1" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-1" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Claude backend now includes <code>--dangerously-skip-permissions</code> — required for write and bash operations since <code>-p</code> mode only permits reads.</li></ul><h2 id="_0-10-0-2026-03-16" tabindex="-1">[0.10.0] - 2026-03-16 <a class="header-anchor" href="#_0-10-0-2026-03-16" aria-label="Permalink to &quot;[0.10.0] - 2026-03-16&quot;">​</a></h2><h3 id="added-2" tabindex="-1">Added <a class="header-anchor" href="#added-2" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>GoReleaser configuration and a tag-driven GitHub Actions release workflow.</li><li>Homebrew tap publishing configuration targeting <code>1broseidon/homebrew-tap</code>.</li><li><code>oa --version</code> and <code>oa version</code> for release verification and package-manager smoke tests.</li></ul><h2 id="_0-9-0-2026-03-16" tabindex="-1">[0.9.0] - 2026-03-16 <a class="header-anchor" href="#_0-9-0-2026-03-16" aria-label="Permalink to &quot;[0.9.0] - 2026-03-16&quot;">​</a></h2><h3 id="added-3" tabindex="-1">Added <a class="header-anchor" href="#added-3" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Pluggable thread storage through a <code>Store</code> interface — use the built-in filesystem store or bring your own.</li><li><code>Client</code> type for applications that embed oneagent, with methods for running, streaming, and managing threads.</li></ul><h2 id="_0-8-0-2026-03-16" tabindex="-1">[0.8.0] - 2026-03-16 <a class="header-anchor" href="#_0-8-0-2026-03-16" aria-label="Permalink to &quot;[0.8.0] - 2026-03-16&quot;">​</a></h2><h3 id="changed" tabindex="-1">Changed <a class="header-anchor" href="#changed" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>Plain text is now the default CLI output mode. Use <code>--json</code> for machine-readable output.</li><li>Added <code>--jsonl</code> as a shortcut for <code>--stream --json</code>.</li></ul><h3 id="added-4" tabindex="-1">Added <a class="header-anchor" href="#added-4" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Dedicated docs for library usage, backend config, and integration examples.</li></ul><h2 id="_0-7-0-2026-03-15" tabindex="-1">[0.7.0] - 2026-03-15 <a class="header-anchor" href="#_0-7-0-2026-03-15" aria-label="Permalink to &quot;[0.7.0] - 2026-03-15&quot;">​</a></h2><h3 id="added-5" tabindex="-1">Added <a class="header-anchor" href="#added-5" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Generic <code>activity</code> events in normalized streaming output, showing what the agent is doing (e.g., reading a file, running a command).</li></ul><h2 id="_0-6-0-2026-03-15" tabindex="-1">[0.6.0] - 2026-03-15 <a class="header-anchor" href="#_0-6-0-2026-03-15" aria-label="Permalink to &quot;[0.6.0] - 2026-03-15&quot;">​</a></h2><h3 id="added-6" tabindex="-1">Added <a class="header-anchor" href="#added-6" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Embedded default backends for Claude, Codex, OpenCode, and Pi — works on first run with no config file.</li><li>Normalized JSONL streaming in both the CLI and Go library.</li></ul><h2 id="_0-5-0-2026-03-15" tabindex="-1">[0.5.0] - 2026-03-15 <a class="header-anchor" href="#_0-5-0-2026-03-15" aria-label="Permalink to &quot;[0.5.0] - 2026-03-15&quot;">​</a></h2><h3 id="added-7" tabindex="-1">Added <a class="header-anchor" href="#added-7" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Compact backend config format — define backends in concise JSON instead of writing Go code.</li></ul><h2 id="_0-4-0-2026-03-15" tabindex="-1">[0.4.0] - 2026-03-15 <a class="header-anchor" href="#_0-4-0-2026-03-15" aria-label="Permalink to &quot;[0.4.0] - 2026-03-15&quot;">​</a></h2><h3 id="added-8" tabindex="-1">Added <a class="header-anchor" href="#added-8" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Portable threads for cross-backend conversation continuity.</li><li>Thread listing, inspection, and compaction commands.</li></ul><h2 id="_0-2-0-2026-03-15" tabindex="-1">[0.2.0] - 2026-03-15 <a class="header-anchor" href="#_0-2-0-2026-03-15" aria-label="Permalink to &quot;[0.2.0] - 2026-03-15&quot;">​</a></h2><h3 id="changed-1" tabindex="-1">Changed <a class="header-anchor" href="#changed-1" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>Improved public API surface and documentation.</li></ul><h2 id="_0-1-0-2026-03-15" tabindex="-1">[0.1.0] - 2026-03-15 <a class="header-anchor" href="#_0-1-0-2026-03-15" aria-label="Permalink to &quot;[0.1.0] - 2026-03-15&quot;">​</a></h2><h3 id="added-9" tabindex="-1">Added <a class="header-anchor" href="#added-9" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Initial release: config-driven multi-agent CLI with normalized JSON output and session resume.</li></ul>',44)])])}const g=a(l,[["render",t]]);export{b as __pageData,g as default};
